<template>
    <div style="width: 80%">
        <div style="margin-bottom: 30px" >编辑图书</div>
        <el-form :inline="true" :rules="rules" ref="ruleForm" :model="form" label-width="100px">
            <el-form-item label="名称" prop="name">
                <el-input v-model="form.name" placeholder="请输入名称"></el-input>
            </el-form-item>
            <el-form-item label="描述" prop="description">
                <el-input style="width: 400px" type="textarea" v-model="form.description" placeholder="请输入描述"></el-input>
            </el-form-item>
            <el-form-item label="出版日期" prop="publishDate">
                <!--                <el-input v-model="form.publish_date" placeholder="请输入出版日期"></el-input>-->
                <el-date-picker
                        v-model="form.publishDate"
                        type="date"
                        value-format="yyyy-MM-dd"

                        placeholder="请输入出版日期">
                </el-date-picker>
            </el-form-item>
            <el-form-item label="分类" prop="category">
<!--
 <el-input v-model="form.category" placeholder="请输入分类"></el-input>-->
                <el-cascader
                        :props="{value: 'name', label: 'name'}"
                        v-model="form.categories"
                        :options="categories"
                       ></el-cascader>
            </el-form-item>
            <el-form-item label="封面" prop="cover">
                <el-input v-model="form.cover" placeholder="请输入封面"></el-input>
            </el-form-item>

        </el-form>
        <div style="text-align: center; margin-top: 30px">
            <el-button type="primary" @click="save">提交</el-button>
        </div>
    </div>
</template>

<script>
    import request from "@/utils/request";
    //导入请求
    export default {
        name: "EditBook",
        data(){
            return {
                form: {},
                categories:[],
                rules: {
                    name: [
                        {required: true, message: '请输入图书名称', trigger: 'blur'},
                    ],
                }
            }

        },
        created() {
            request.get('/category/tree').then(res => {
                this.categories = res.data;
            })
            const id = this.$route.query.id
            request.get("/book/" + id).then(res =>{
                this.form = res.data
                if(this.form.category){
                    this.form.categories = this.form.category.split('>')
                }
            })
        },
        methods: {
            save() {
                request.put('/book/update',this.form).then(res =>{
                    if(res.code === '200'){
                        this.$notify.success('更新成功')
                        this.$router.push("/bookList")
                    }else{
                        this.$notify.error(res.msg)
                    }
                })
                //    对接的是后台的UserController.java文件的路径
            }
        }
    }
</script>
